// Special codes for quick access
export const ORIGIN_SPECIAL_CODES = {
  DOMESTIC: '0',           // domestic (Korean)
  SHOW_IN_DETAIL: '3',     // shown in product detail
  DIRECT_INPUT: '4',       // direct input
  NOT_REQUIRED: '5',       // origin marking not required
} as const;

// Search helper: filter by name (Korean) or code
export function searchOriginCodes(query: string): OriginCode[] {
  if (!query.trim()) return NAVER_ORIGIN_CODES.slice(0, 20);
  const q = query.toLowerCase().trim();
  return NAVER_ORIGIN_CODES.filter(
    (o) => o.name.toLowerCase().includes(q) || o.code.includes(q)
  );
}
